@page "/chat"
@layout Components.Layout.ChatLayout
@rendermode InteractiveServer
@using System.Globalization
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="chat-container">
    @* ── Left Sidebar: Channel List ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h2>Channels</h2>
        </div>
        <ul class="channel-list">
            @foreach (var channel in channels)
            {
                <li class="channel-item @(channel.Id == activeChannelId ? "active" : "")"
                    @onclick="() => SelectChannelAsync(channel)">
                    <div class="channel-name"># @channel.Name</div>
                    <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </li>
            }
        </ul>
    </aside>

    @* ── Main Message Area ── *@
    <section class="message-area @(threadOpen ? "" : "expanded")">
        @if (activeChannel is not null)
        {
            <div class="message-header">
                <h3># @activeChannel.Name</h3>
                <span class="header-desc">@activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="messageListRef">
                @if (isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (!hasMoreMessages && messages.Count > 0)
                {
                    <div class="beginning-notice">Beginning of channel history</div>
                }
                @foreach (var msg in messages)
                {
                    <div class="message-bubble" @onmouseenter="() => hoveredMessageId = msg.Id"
                         @onmouseleave="() => hoveredMessageId = null">
                        <div class="message-meta">
                            <span class="author">@msg.Author</span>
                            <span class="timestamp">@FormatRelativeTime(msg.SentAt)</span>
                        </div>
                        <div class="message-content">@msg.Content</div>

                        @* Reactions *@
                        @if (msg.Reactions.Count > 0)
                        {
                            <div class="reactions-row">
                                @foreach (var r in msg.Reactions)
                                {
                                    <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                            @onclick="() => AddReactionAsync(msg.Id, r.Emoji)">
                                        @r.Emoji @r.Users.Count
                                    </button>
                                }
                            </div>
                        }

                        @* Thread summary link *@
                        @{
                            var thread = threadSummaries.FirstOrDefault(t => t.RootMessageId == msg.Id);
                        }
                        @if (thread is not null)
                        {
                            <button class="thread-link" @onclick="() => OpenThreadAsync(msg.Id)">
                                @thread.ReplyCount @(thread.ReplyCount == 1 ? "reply" : "replies")
                                — last @FormatRelativeTime(thread.LastReplyAt)
                            </button>
                        }

                        @* Hover action buttons *@
                        @if (hoveredMessageId == msg.Id)
                        {
                            <div class="message-actions">
                                <button class="action-btn" @onclick="() => OpenThreadAsync(msg.Id)" title="Reply in thread">
                                    💬 Reply
                                </button>
                                <div class="emoji-picker-wrapper">
                                    <button class="action-btn" @onclick="() => ToggleEmojiPicker(msg.Id)" title="Add reaction">
                                        😀 React
                                    </button>
                                    @if (emojiPickerMessageId == msg.Id)
                                    {
                                        <div class="emoji-picker">
                                            @foreach (var emoji in commonEmojis)
                                            {
                                                <button class="emoji-option" @onclick="() => AddReactionAsync(msg.Id, emoji)">
                                                    @emoji
                                                </button>
                                            }
                                        </div>
                                    }
                                </div>
                            </div>
                        }
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="newMessageText" @bind:event="oninput"
                          @onkeydown="HandleMainKeyDown"
                          placeholder="Type a message…" rows="2"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right Panel: Thread View ── *@
    @if (threadOpen)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            @if (threadRootMessage is not null)
            {
                <div class="thread-root-quote">
                    <div class="message-meta">
                        <span class="author">@threadRootMessage.Author</span>
                        <span class="timestamp">@FormatRelativeTime(threadRootMessage.SentAt)</span>
                    </div>
                    <div class="message-content">@threadRootMessage.Content</div>
                </div>

                <div class="thread-divider">
                    <span>@threadReplies.Count @(threadReplies.Count == 1 ? "reply" : "replies")</span>
                </div>

                <div class="thread-messages">
                    @foreach (var reply in threadReplies)
                    {
                        <div class="message-bubble">
                            <div class="message-meta">
                                <span class="author">@reply.Author</span>
                                <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-content">@reply.Content</div>

                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reactions-row">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => AddReactionAsync(reply.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    }
                </div>

                <div class="message-input-area">
                    <textarea @bind="threadReplyText" @bind:event="oninput"
                              @onkeydown="HandleThreadKeyDown"
                              placeholder="Reply in thread…" rows="2"></textarea>
                    <button class="send-btn" @onclick="SendThreadReplyAsync" disabled="@string.IsNullOrWhiteSpace(threadReplyText)">
                        Reply
                    </button>
                </div>
            }
        </aside>
    }
</div>

@code {
    private List<Channel> channels = new();
    private List<Message> messages = new();
    private List<ThreadSummary> threadSummaries = new();
    private List<Message> threadReplies = new();
    private Message? threadRootMessage;

    private int activeChannelId;
    private Channel? activeChannel;
    private bool threadOpen;
    private int? hoveredMessageId;
    private int? emojiPickerMessageId;

    private string newMessageText = "";
    private string threadReplyText = "";

    private const int PageSize = 30;
    private int currentSkip;
    private bool hasMoreMessages = true;
    private bool isLoadingMore;

    private ElementReference messageListRef;
    private IJSObjectReference? jsModule;

    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "😮", "🚀"];

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannelAsync(channels[0]);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            jsModule = await JS.InvokeAsync<IJSObjectReference>("import",
                "./Components/Pages/Chat.razor.js");
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        activeChannel = channel;
        activeChannelId = channel.Id;
        currentSkip = 0;
        hasMoreMessages = true;
        messages.Clear();
        emojiPickerMessageId = null;

        var loaded = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        messages = loaded;
        currentSkip = loaded.Count;
        hasMoreMessages = loaded.Count == PageSize;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channel list to clear unread badge
        channels = await ChatService.GetChannelsAsync();

        await ScrollToBottom();
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (isLoadingMore || !hasMoreMessages) return;
        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannelId, currentSkip, PageSize);
        if (older.Count < PageSize) hasMoreMessages = false;
        currentSkip += older.Count;

        // Prepend older messages
        messages.InsertRange(0, older);
        BuildThreadSummaries();

        isLoadingMore = false;
    }

    private void BuildThreadSummaries()
    {
        // Build summaries from messages that have replies referencing them
        var roots = messages.Where(m => m.ReplyToId is null).Select(m => m.Id).ToHashSet();
        var grouped = messages.Where(m => m.ReplyToId is not null && roots.Contains(m.ReplyToId.Value))
                              .GroupBy(m => m.ReplyToId!.Value);

        threadSummaries = grouped.Select(g => new ThreadSummary(
            g.Key,
            g.Count(),
            g.Max(m => m.SentAt)
        )).ToList();
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText)) return;

        var sent = await ChatService.SendMessageAsync(activeChannelId, newMessageText.Trim(), null);
        messages.Add(sent);
        newMessageText = "";
        BuildThreadSummaries();
        await ScrollToBottom();
    }

    private async Task HandleMainKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessageAsync();
        }
    }

    private async Task OpenThreadAsync(int rootMessageId)
    {
        threadOpen = true;
        emojiPickerMessageId = null;
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        var allThreadMessages = await ChatService.GetThreadAsync(rootMessageId);
        // Exclude root message from replies
        threadReplies = allThreadMessages.Where(m => m.Id != rootMessageId).ToList();
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies.Clear();
        threadReplyText = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannelId, threadReplyText.Trim(), threadRootMessage.Id);
        threadReplies.Add(reply);
        messages.Add(reply);
        threadReplyText = "";
        BuildThreadSummaries();
    }

    private async Task HandleThreadKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendThreadReplyAsync();
        }
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        emojiPickerMessageId = null;

        // Refresh messages to show updated reactions
        if (activeChannel is not null)
        {
            var refreshed = await ChatService.GetMessagesAsync(activeChannelId, 0, currentSkip);
            messages = refreshed;
            BuildThreadSummaries();
        }

        // Refresh thread if open
        if (threadOpen && threadRootMessage is not null)
        {
            var allThreadMessages = await ChatService.GetThreadAsync(threadRootMessage.Id);
            threadRootMessage = allThreadMessages.FirstOrDefault(m => m.Id == threadRootMessage.Id) ?? threadRootMessage;
            threadReplies = allThreadMessages.Where(m => m.Id != threadRootMessage.Id).ToList();
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task ScrollToBottom()
    {
        await Task.Yield();
        if (jsModule is not null)
        {
            try
            {
                await jsModule.InvokeVoidAsync("scrollToBottom", messageListRef);
            }
            catch (JSDisconnectedException) { }
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        await LoadOlderMessagesAsync();
        StateHasChanged();
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy", CultureInfo.InvariantCulture);
    }

    private static string TruncateDescription(string desc)
    {
        return desc.Length > 40 ? desc[..37] + "…" : desc;
    }

    public async ValueTask DisposeAsync()
    {
        if (jsModule is not null)
        {
            try { await jsModule.DisposeAsync(); }
            catch (JSDisconnectedException) { }
        }
    }
}

